export function getPharmTechMedicationBySlug(slug: string): PharmTechMedication | undefined {
  return PHARMTECH_MEDICATIONS.find(m => m.slug === slug);
}

export function getRelatedMedications(currentSlug: string, count: number = 4): PharmTechMedication[] {
  const current = getPharmTechMedicationBySlug(currentSlug);
  if (!current) return PHARMTECH_MEDICATIONS.slice(0, count);
  const related = current.relatedMedications
    .map(slug => getPharmTechMedicationBySlug(slug))
    .filter((m): m is PharmTechMedication => m !== undefined);
  if (related.length >= count) return related.slice(0, count);
  const remaining = PHARMTECH_MEDICATIONS
    .filter(m => m.slug !== currentSlug && !current.relatedMedications.includes(m.slug))
    .slice(0, count - related.length);
  return [...related, ...remaining];
}
